surface.template:
precision highp float;
{{meta}}
#ifndef SHADING_UNLIT
#ifndef SHADING_TOON
#ifndef SHADING_PBR
#define SHADING_PBR 1
#endif
#endif
#endif

// Varyings from default vertex shader
varying vec2 vUv;
varying vec3 vNormal;
varying vec3 vViewPosition;

// Simple preview lighting uniforms (parsed and set by preview panel)
uniform vec3 uLightDir = vec3(0.5, 0.8, 0.6);
uniform vec3 uLightColor = vec3(3.0, 3.0, 3.0);
uniform vec3 uAmbient = vec3(0.15, 0.15, 0.15);
uniform float uExposure = 1.4;

// PBR helpers
float saturate(float x) { return clamp(x, 0.0, 1.0); }
vec3 saturate(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
float D_GGX(float NoH, float a) { float a2 = a*a; float f = (NoH * NoH) * (a2 - 1.0) + 1.0; return a2 / (3.14159265 * f * f + 1e-5); }
float V_SmithGGXCorrelated(float NoV, float NoL, float a) { float a2 = a*a; float gv = NoL * sqrt((NoV - NoV * a2) * NoV + a2); float gl = NoV * sqrt((NoL - NoL * a2) * NoL + a2); return 0.5 / max(gv + gl, 1e-5); }
vec3 F_Schlick(vec3 f0, float VoH) { float f = pow(1.0 - VoH, 5.0); return f + (1.0 - f) * f0; }
vec3 BRDF_Lambert(vec3 diffuseColor) { return diffuseColor / 3.14159265; }

{{exposed_nodes}}
{{internal_nodes}}

fragment_output.template:
#if defined(SHADING_PBR)
vec3 baseColor = vec3({{inputs:0}});
float roughness = clamp({{inputs:1}}, 0.04, 1.0);
float metalness = clamp({{inputs:2}}, 0.0, 1.0);
vec3 emission = vec3({{inputs:3}});
vec3 nrm_in = vec3({{inputs:4}});
float alpha = {{inputs:5}};
// Combine geometry normal with input delta (so default (0,0,1) means keep vNormal)
vec3 N = normalize(vNormal + (nrm_in - vec3(0.0, 0.0, 1.0)));
vec3 V = normalize(vViewPosition);
vec3 L = normalize(uLightDir);
vec3 H = normalize(V + L);
float NoV = saturate(dot(N, V));
float NoL = saturate(dot(N, L));
float NoH = saturate(dot(N, H));
float VoH = saturate(dot(V, H));
float a = max(0.001, roughness * roughness);
vec3 f0 = mix(vec3(0.04), baseColor, metalness);
float D = D_GGX(NoH, a);
float Vis = V_SmithGGXCorrelated(NoV, NoL, a);
vec3  F = F_Schlick(f0, VoH);
vec3  Fr = (D * Vis) * F;
vec3  kd = (1.0 - F) * (1.0 - metalness);
vec3  diffuse = BRDF_Lambert(baseColor) * kd;
vec3  Lo = (diffuse + Fr) * (uLightColor * NoL) + uAmbient * baseColor;
vec3  color = saturate((Lo + emission) * uExposure);
gl_FragColor = vec4(color, alpha);
#elif defined(SHADING_TOON)
vec3 baseColor = vec3({{inputs:0}});
float alpha = {{inputs:5}};
vec3 N = normalize(vNormal);
vec3 L = normalize(uLightDir);
float ndl = max(dot(N, L), 0.0);
float ramp = step(0.2, ndl) + step(0.6, ndl);
ramp = clamp(ramp, 0.0, 1.0);
vec3 color = mix(baseColor * 0.6, baseColor, ramp);
gl_FragColor = vec4(color, alpha);
#else
// Unlit fallback
gl_FragColor = vec4({{inputs:0}}, {{inputs:5}});
#endif
